/**
* salt dependent update with random access
*
* @param g		garlic
* @param x		hash array
* @param gamma	gamma
* @return		hash array
*/
    private byte[][] gamma(int g, byte[][] x, byte[] gamma) {
        return this.get_gamma().gamma(g, x, gamma);
    }

    public byte[][] gamma(int var1, byte[][] var2, byte[] var3);


    public byte[][] gamma(int g, byte[][] x, byte[] gamma) {
